function trackById(id) { return STARTUP_TRACKS.find(t => t.id === id); }
function trackByName(name) { return STARTUP_TRACKS.find(t => t.name === name); }
// 给某年(year)挑选立项可见的赛道：当年真风口 + 同期/邻近的热门泡沫 + 长青，混在一起让玩家自己甄别
function tracksForEra(year, eraWindName) {
  const wind = eraWindName ? STARTUP_TRACKS.find(t => t.name === eraWindName) : null;
  // 当年「显得热」的：泡沫(era 含当下年代关键字不易判，简化为随机抽)，加几个长青/小众
  const bubbles = STARTUP_TRACKS.filter(t => t.kind === "bubble");
  const stable = STARTUP_TRACKS.filter(t => t.kind === "evergreen" || t.kind === "niche");
  return { wind, bubbles, stable };
}
const TRACK_NAMES = STARTUP_TRACKS.map(t => t.name);

if (typeof window !== "undefined") {
  window.STARTUP_TRACKS = STARTUP_TRACKS;
  window.trackById = trackById; window.trackByName = trackByName;
  window.tracksForEra = tracksForEra; window.TRACK_NAMES = TRACK_NAMES;
}
